@using sv_b5e71b46fc664ecb989be852ecb85ad4.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

<div class="catalog-container">
    <!-- Left Sidebar -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Category</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
            else
            {
                <p class="text-muted">Loading categories…</p>
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <div class="price-inputs">
                <label>
                    Min
                    <input type="number" min="0" step="0.01" @bind="minPrice" placeholder="Min" />
                </label>
                <label>
                    Max
                    <input type="number" min="0" step="0.01" @bind="maxPrice" placeholder="Max" />
                </label>
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <main class="catalog-main">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-link" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="loading-indicator">
                <p>Loading products…</p>
            </div>
        }
        else if (searchResult is not null && searchResult.Items.Count == 0)
        {
            <div class="empty-results">
                <p>No products found matching your filters.</p>
                <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
            </div>
        }
        else if (searchResult is not null)
        {
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label for="sort-select">Sort by:</label>
                    <select id="sort-select" @bind="sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="results-summary">
                    Showing @(((searchResult.Page - 1) * searchResult.PageSize) + 1)–@(Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount))
                    of @searchResult.TotalCount products
                </span>
            </div>

            <!-- Product Grid -->
            <div class="product-grid">
                @foreach (var product in searchResult.Items)
                {
                    <div class="product-card" @onclick="() => OnProductSelected(product)">
                        <div class="product-image" title="@product.Name">
                            <span>@product.Name</span>
                        </div>
                        <div class="product-info">
                            <h5 class="product-name">@product.Name</h5>
                            <p class="product-price">@product.Price.ToString("C")</p>
                            <p class="product-rating">@GetStarRating(product.Rating)</p>
                            @if (!product.InStock)
                            {
                                <span class="badge badge-out-of-stock">Out of Stock</span>
                            }
                            <button class="btn btn-cart"
                                    disabled="@(!product.InStock)"
                                    @onclick="() => AddToCart(product)"
                                    @onclick:stopPropagation="true">
                                Add to Cart
                            </button>
                        </div>
                    </div>
                }
            </div>

            <!-- Pagination -->
            <nav class="pagination-controls">
                <button class="btn btn-page"
                        disabled="@(currentPage <= 1)"
                        @onclick="() => GoToPage(currentPage - 1)">
                    Previous
                </button>

                @for (int i = 1; i <= totalPages; i++)
                {
                    var pageNum = i;
                    <button class="btn btn-page @(pageNum == currentPage ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }

                <button class="btn btn-page"
                        disabled="@(currentPage >= totalPages)"
                        @onclick="() => GoToPage(currentPage + 1)">
                    Next
                </button>
            </nav>
        }
    </main>
</div>

